PlayerStats.cs

using UnityEngine;

public class PlayerStats : MonoBehaviour
{
    public int MaxHealth = 100;
    public int CurrentHealth;
    public int Currency = 0;

    void Awake()
    {
        CurrentHealth = MaxHealth;
    }

    // Call this method when the player takes damage
    public void TakeDamage(int amount)
    {
        CurrentHealth -= amount;
        if (CurrentHealth < 0)
        {
            CurrentHealth = 0;
            Debug.Log("Player defeated!");
            // Implement game over logic here
        }
        Debug.Log($"Player took {amount} damage. Current Health: {CurrentHealth}");
    }

    // Call this method when the player gains currency
    public void AddCurrency(int amount)
    {
        Currency += amount;
        Debug.Log($"Gained {amount} currency. Total Currency: {Currency}");
    }

    // Call this method when the player attempts to spend currency
    public bool TrySpendCurrency(int amount)
    {
        if (Currency >= amount)
        {
            Currency -= amount;
            Debug.Log($"Spent {amount} currency. Remaining Currency: {Currency}");
            return true;
        }
        else
        {
            Debug.Log($"Not enough currency to spend {amount}. Current Currency: {Currency}");
            return false;
        }
    }

    // Healing method
    public void Heal(int amount)
    {
        CurrentHealth += amount;
        if (CurrentHealth > MaxHealth)
        {
            CurrentHealth = MaxHealth;
        }
        Debug.Log($"Player healed {amount}. Current Health: {CurrentHealth}");
    }
}

