    public PlayerStats PlayerStatsRef; // Reference to the PlayerStats script

    void Start()
    {
        // Find the player stats if not assigned in the inspector
        if (PlayerStatsRef == null)
        {
            PlayerStatsRef = FindObjectOfType<PlayerStats>();
            if (PlayerStatsRef == null)
            {
                Debug.LogError("PlayerStats not found in the scene! Please ensure a PlayerStats script is present.");
            }
        }
    }

    // Call this method when the enemy attacks the player (e.g., on collision, timer, etc.)
    public void AttackPlayer()
    {
        if (PlayerStatsRef != null)
        {
            PlayerStatsRef.TakeDamage(DamageAmount);
        }
        else
        {
            Debug.LogWarning("Cannot attack, PlayerStats reference is missing.");
        }
    }

    // Example trigger for attack (e.g., when player enters collider)
    void OnTriggerEnter(Collider other)
    {
        if (other.CompareTag("Player")) // Make sure your player GameObject has the tag "Player"
        {
            AttackPlayer();
        }
    }
}

ShopItem.cs (ScriptableObject)

using UnityEngine;

[CreateAssetMenu(fileName = "NewShopItem", menuName = "Game/Shop Item")]
public class ShopItem : ScriptableObject
{
    public enum ItemType
    {
        HealthPotion,
        CoinPack,
        WeaponUpgrade,
        ArmorUpgrade
    }

    public string ItemName = "New Item";
    public string Description = "A useful item.";
    public int Price = 10;
    public ItemType Type = ItemType.HealthPotion;
    public int Value = 1; // Amount of health, coins, or upgrade level

    // This method applies the item's effect to the player
    public void ApplyEffect(PlayerStats player)
    {
        switch (Type)
        {
            case ItemType.HealthPotion:
                player.Heal(Value);
                Debug.Log($"{ItemName} applied! Player healed {Value}.");
                break;
            case ItemType.CoinPack:
                player.AddCurrency(Value);
                Debug.Log($"{ItemName} applied! Gained {Value} currency.");
                break;
            case ItemType.WeaponUpgrade:
                // Implement weapon upgrade logic here (e.g., increase player attack stat)
                Debug.Log($"{ItemName} applied! Weapon upgraded by {Value}.");
                break;
            case ItemType.ArmorUpgrade:
                // Implement armor upgrade logic here (e.g., increase player defense stat)
                Debug.Log($"{ItemName} applied! Armor upgraded by {Value}.");
                break;
            default:
                Debug.LogWarning($"Unknown item type: {Type} for {ItemName}");
                break;
        }
    }
}

