using UnityEngine;
using System.Collections.Generic; // Useful if you want to use Lists instead of arrays

public class ShopManager : MonoBehaviour
{
    public PlayerStats PlayerStatsRef; // Reference to the PlayerStats script
    public ShopItem[] AvailableItems; // Array of ShopItem ScriptableObjects

    void Start()
    {
        // Find the player stats if not assigned in the inspector
        if (PlayerStatsRef == null)
        {
            PlayerStatsRef = FindObjectOfType<PlayerStats>();
            if (PlayerStatsRef == null)
            {
                Debug.LogError("PlayerStats not found in the scene! Please ensure a PlayerStats script is present.");
            }
        }

        Debug.Log("--- Shop Items Available ---");
        DisplayShopItems();
    }

    // Displays all available items (for example, in the console)
    public void DisplayShopItems()
    {
        if (AvailableItems == null || AvailableItems.Length == 0)
        {
            Debug.Log("No items available in the shop.");
            return;
        }

        for (int i = 0; i < AvailableItems.Length; i++)
        {
            ShopItem item = AvailableItems[i];
            Debug.Log($"[{i}] {item.ItemName} - {item.Description} - Price: {item.Price} currency.");
        }
        Debug.Log($"Current Player Currency: {PlayerStatsRef.Currency}");
    }

    // Call this method when a player attempts to purchase an item
    public void PurchaseItem(ShopItem itemToBuy)
    {
        if (PlayerStatsRef == null)
        {
            Debug.LogError("PlayerStats reference is missing, cannot process purchase.");
            return;
        }
        if (itemToBuy == null)
        {
            Debug.LogError("Attempted to purchase a null item.");
            return;
        }

        Debug.Log($"Attempting to purchase {itemToBuy.ItemName} for {itemToBuy.Price} currency.");

        if (PlayerStatsRef.TrySpendCurrency(itemToBuy.Price))
        {
            // Successfully spent currency, now apply item effect
            itemToBuy.ApplyEffect(PlayerStatsRef);
            Debug.Log($"Successfully purchased {itemToBuy.ItemName}.");
        }
        else
        {
            Debug.Log($"Purchase failed for {itemToBuy.ItemName}. Not enough currency.");
        }
        Debug.Log($"Current Player Currency: {PlayerStatsRef.Currency}");
    }

    // Example usage for testing purposes, you would link this to UI buttons
    public void PurchaseItemByIndex(int index)
    {
        if (index >= 0 && index < AvailableItems.Length)
        {
            PurchaseItem(AvailableItems[index]);
        }
        else
        {
            Debug.LogError($"Invalid item index: {index}.");
        }
    }
}

How to use:

1.  Create an empty GameObject in your Unity scene named "Player" and attach the `PlayerStats.cs` script to it.
2.  Create another empty GameObject named "ShopManager" and attach the `ShopManager.cs` script to it.
3.  In the Project window, right-click -> Create -> Game -> Shop Item. Create several `ShopItem` assets (e.g., "HealthPotion", "CoinPackSmall", "WeaponUpgrade1").
    *   Set their `ItemName`, `Description`, `Price`, `Type`, and `Value` (e.g., HealthPotion: Type=HealthPotion, Value=25; CoinPackSmall: Type=CoinPack, Value=100; WeaponUpgrade1: Type=WeaponUpgrade, Value=1).
4.  Select the "ShopManager" GameObject in the Hierarchy. In its Inspector, drag your created `ShopItem` assets into the `AvailableItems` array.
5.  Create an empty GameObject named "Enemy" and attach the `Enemy.cs` script to it. You can set its `DamageAmount`. Ensure it has a Collider set to `Is Trigger` and its `PlayerStatsRef` is set to your "Player" GameObject. Make sure your "Player" GameObject has a Collider and its Tag is set to "Player".
6.  Run the game. Check the console for logs regarding health, currency, and purchases.
7.  To test purchases, you can manually call `ShopManager.PurchaseItemByIndex(int index)` from another script or a UI button, for example:
    *   Find the `ShopManager` instance: `FindObjectOfType<ShopManager>().PurchaseItemByIndex(0);`